+          }
+          try {
+            Thread.sleep(1);
+          } catch (InterruptedException e) {
+            throw new RuntimeException(e);
+          }
+        }
+      });
+      thread.start();
+      threads[i] = thread;
+    }
+    barrier.await();
+    for (int i = 0;i < numThreads;i++) {
